      relatedFaqSlugs: ["can-you-build-an-adobe-or-rammed-earth-home-in-arizona", "how-to-design-a-custom-home-to-stay-cool-in-the-arizona-heat", "what-is-a-courtyard-home-and-does-the-design-work-in-the-arizona-desert", "what-is-a-territorial-style-home-in-arizona", "what-are-lrv-paint-color-rules-in-north-scottsdale-luxury-communities", "what-roof-types-and-slopes-do-luxury-arizona-communities-allow"],
      relatedServiceSlugs: ["custom-homes"],
