      tags: ["water-septic", "research-phase"],
      relatedFaqSlugs: ["do-i-need-a-whole-house-water-softener-or-treatment-system-on-a-new-arizona-home", "how-deep-do-you-have-to-drill-a-well-in-arizona", "what-is-an-adwr-notice-of-intent-to-drill-a-well", "what-is-a-shared-well-agreement-in-arizona", "what-do-i-need-to-build-on-rural-land-in-rio-verde-arizona", "how-close-can-a-well-be-to-a-septic-system-in-arizona"],
      relatedServiceSlugs: ["custom-homes", "build-on-your-lot"],
